// SPDX-License-Identifier: MIT
pragma solidity 0.8.25;

// Testing utilities
import { Test } from "forge-std/Test.sol";

// Libraries
import { Predeploys } from "src/libraries/Predeploys.sol";
import { SuperchainERC20 } from "src/L2/SuperchainERC20.sol";
import { ProtocolGuided } from "./fuzz/Protocol.guided.t.sol";
import { ProtocolUnguided } from "./fuzz/Protocol.unguided.t.sol";
import { HandlerGetters } from "./helpers/HandlerGetters.t.sol";
import { MockL2ToL2CrossDomainMessenger } from "./helpers/MockL2ToL2CrossDomainMessenger.t.sol";

contract OptimismSuperchainERC20Handler is HandlerGetters, ProtocolGuided, ProtocolUnguided { }

contract OptimismSuperchainERC20Properties is Test {
    OptimismSuperchainERC20Handler internal handler;
    MockL2ToL2CrossDomainMessenger internal constant MESSENGER =
        MockL2ToL2CrossDomainMessenger(Predeploys.L2_TO_L2_CROSS_DOMAIN_MESSENGER);

    function setUp() public {
        handler = new OptimismSuperchainERC20Handler();
        targetContract(address(handler));
    }

    // TODO: will need rework after
    //   - `convert`
    /// @custom:invariant sum of supertoken total supply across all chains is always <= to convert(legacy, super)-
    /// convert(super, legacy)
    function invariant_totalSupplyAcrossChainsEqualsMintsMinusFundsInTransit() external view {
        // iterate over unique deploy salts aka supertokens that are supposed to be compatible with each other
        for (uint256 deploySaltIndex = 0; deploySaltIndex < handler.deploySaltsLength(); deploySaltIndex++) {
            uint256 totalSupply = 0;
            (bytes32 currentSalt, uint256 trackedSupply) = handler.totalSupplyAcrossChainsAtIndex(deploySaltIndex);
            uint256 fundsInTransit = handler.tokensInTransitForDeploySalt(currentSalt);
            // and then over all the (mocked) chain ids where that supertoken could be deployed
            for (uint256 validChainId = 0; validChainId < handler.MAX_CHAINS(); validChainId++) {
                address supertoken = MESSENGER.superTokenAddresses(validChainId, currentSalt);
                if (supertoken != address(0)) {
                    totalSupply += SuperchainERC20(supertoken).totalSupply();
                }
            }
            assertEq(trackedSupply, totalSupply + fundsInTransit);
        }
    }

    // TODO: will need rework after
    //   - `convert`
    /// @custom:invariant sum of supertoken total supply across all chains is equal to convert(legacy, super)-
    /// convert(super, legacy) when all when all cross-chain messages are processed
    function invariant_totalSupplyAcrossChainsEqualsMintsWhenQueueIsEmpty() external view {
        if (MESSENGER.messageQueueLength() != 0) {
            return;
        }
        // iterate over unique deploy salts aka supertokens that are supposed to be compatible with each other
        for (uint256 deploySaltIndex = 0; deploySaltIndex < handler.deploySaltsLength(); deploySaltIndex++) {
            uint256 totalSupply = 0;
            (bytes32 currentSalt, uint256 trackedSupply) = handler.totalSupplyAcrossChainsAtIndex(deploySaltIndex);
            // and then over all the (mocked) chain ids where that supertoken could be deployed
            for (uint256 validChainId = 0; validChainId < handler.MAX_CHAINS(); validChainId++) {
                address supertoken = MESSENGER.superTokenAddresses(validChainId, currentSalt);
                if (supertoken != address(0)) {
                    totalSupply += SuperchainERC20(supertoken).totalSupply();
                }
            }
            assertEq(trackedSupply, totalSupply);
        }
    }

    /// @custom:invariant many other assertion mode invariants are also defined  under
    /// `test/invariants/SuperchainERC20/fuzz/` .
    ///
    ///     since setting`fail_on_revert=false` also ignores StdAssertion failures, this invariant explicitly asks the
    ///     handler for assertion test failures
    function invariant_handlerAssertions() external view {
        assertFalse(handler.failed());
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.25;

import { MockL2ToL2CrossDomainMessenger } from "../helpers/MockL2ToL2CrossDomainMessenger.t.sol";
import { SuperchainERC20 } from "src/L2/SuperchainERC20.sol";
import { ProtocolHandler } from "../handlers/Protocol.t.sol";
import { EnumerableMap } from "@openzeppelin/contracts/utils/structs/EnumerableMap.sol";
import { CompatibleAssert } from "../helpers/CompatibleAssert.t.sol";

contract ProtocolGuided is ProtocolHandler, CompatibleAssert {
    using EnumerableMap for EnumerableMap.Bytes32ToUintMap;
    /// @notice deploy a new supertoken with deploy salt determined by params, to the given (of course mocked) chainId
    /// @custom:property-id 14
    /// @custom:property supertoken total supply starts at zero

    function fuzz_deployNewSupertoken(
        TokenDeployParams memory params,
        uint256 chainId
    )
        external
        validateTokenDeployParams(params)
    {
        chainId = bound(chainId, 0, MAX_CHAINS - 1);
        SuperchainERC20 supertoken = _deploySupertoken(
            remoteTokens[params.remoteTokenIndex],
            WORDS[params.nameIndex],
            WORDS[params.symbolIndex],
            DECIMALS[params.decimalsIndex],
            chainId
        );
        // 14
        compatibleAssert(supertoken.totalSupply() == 0);
    }

    /// @custom:property-id 11
    /// @custom:property relayERC20 increases the token's totalSupply in the destination chain exactly by the input
    /// amount
    /// @custom:property-id 27
    /// @custom:property relayERC20 increases sender's balance in the destination chain exactly by the input amount
    /// @custom:property-id 7
    /// @custom:property calls to relayERC20 always succeed as long as the cross-domain caller is valid
    function fuzz_relayERC20(uint256 messageIndex) external {
        MockL2ToL2CrossDomainMessenger.CrossChainMessage memory messageToRelay = MESSENGER.messageQueue(messageIndex);
        SuperchainERC20 destinationToken = SuperchainERC20(messageToRelay.crossDomainMessageSender);
        uint256 destinationSupplyBefore = destinationToken.totalSupply();
        uint256 destinationBalanceBefore = destinationToken.balanceOf(messageToRelay.recipient);

        try MESSENGER.relayMessageFromQueue(messageIndex) {
            bytes32 deploySalt = MESSENGER.superTokenInitDeploySalts(address(destinationToken));
            (bool success, uint256 currentlyInTransit) = ghost_tokensInTransit.tryGet(deploySalt);
            // if sendERC20 didnt initialize this, then test suite is broken
            compatibleAssert(success);
            ghost_tokensInTransit.set(deploySalt, currentlyInTransit - messageToRelay.amount);
            // 11
            compatibleAssert(destinationSupplyBefore + messageToRelay.amount == destinationToken.totalSupply());
            // 27
            compatibleAssert(
                destinationBalanceBefore + messageToRelay.amount == destinationToken.balanceOf(messageToRelay.recipient)
            );
        } catch {
            // 7
            compatibleAssert(false);
        }
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.25;

import { ProtocolHandler } from "../handlers/Protocol.t.sol";
import { EnumerableMap } from "@openzeppelin/contracts/utils/structs/EnumerableMap.sol";
import { OptimismSuperchainERC20 } from "src/L2/OptimismSuperchainERC20.sol";
import { CompatibleAssert } from "../helpers/CompatibleAssert.t.sol";

// TODO: add fuzz_sendERC20 when we implement non-atomic bridging
contract ProtocolUnguided is ProtocolHandler, CompatibleAssert {
    using EnumerableMap for EnumerableMap.Bytes32ToUintMap;

    /// @custom:property-id 12
    /// @custom:property supertoken total supply only increases on calls to mint() by the L2toL2StandardBridge
    function fuzz_mint(uint256 tokenIndex, address to, address sender, uint256 amount) external {
        address token = allSuperTokens[bound(tokenIndex, 0, allSuperTokens.length)];
        bytes32 salt = MESSENGER.superTokenInitDeploySalts(token);
        amount = bound(amount, 0, type(uint256).max - OptimismSuperchainERC20(token).totalSupply());
        vm.prank(sender);
        try OptimismSuperchainERC20(token).crosschainMint(to, amount) {
            compatibleAssert(sender == BRIDGE);
            (, uint256 currentValue) = ghost_totalSupplyAcrossChains.tryGet(salt);
            ghost_totalSupplyAcrossChains.set(salt, currentValue + amount);
        } catch {
            compatibleAssert(sender != BRIDGE || to == address(0));
        }
    }

    /// @custom:property-id 13
    /// @custom:property supertoken total supply only increases on calls to mint() by the L2toL2StandardBridge
    function fuzz_burn(uint256 tokenIndex, address from, address sender, uint256 amount) external {
        address token = allSuperTokens[bound(tokenIndex, 0, allSuperTokens.length)];
        bytes32 salt = MESSENGER.superTokenInitDeploySalts(token);
        uint256 senderBalance = OptimismSuperchainERC20(token).balanceOf(sender);
        vm.prank(sender);
        try OptimismSuperchainERC20(token).crosschainBurn(from, amount) {
            compatibleAssert(sender == BRIDGE);
            (, uint256 currentValue) = ghost_totalSupplyAcrossChains.tryGet(salt);
            ghost_totalSupplyAcrossChains.set(salt, currentValue - amount);
        } catch {
            compatibleAssert(sender != BRIDGE || senderBalance < amount);
        }
    }

    /// @custom:property-id 25
    /// @custom:property supertokens can't be reinitialized
    function fuzz_initialize(
        address sender,
        uint256 tokenIndex,
        address remoteToken,
        string memory name,
        string memory symbol,
        uint8 decimals
    )
        external
    {
        vm.prank(sender);
        // revert is possible in bound, but is not part of the external call
        try OptimismSuperchainERC20(allSuperTokens[bound(tokenIndex, 0, allSuperTokens.length)]).initialize(
            remoteToken, name, symbol, decimals
        ) {
            compatibleAssert(false);
        } catch { }
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.25;

import { TestBase } from "forge-std/Base.sol";
import { StdUtils } from "forge-std/StdUtils.sol";

import { ERC1967Proxy } from "@openzeppelin/contracts-v5/proxy/ERC1967/ERC1967Proxy.sol";
import { EnumerableMap } from "@openzeppelin/contracts/utils/structs/EnumerableMap.sol";
import { OptimismSuperchainERC20 } from "src/L2/OptimismSuperchainERC20.sol";
import { OptimismSuperchainERC20ForToBProperties } from "../helpers/OptimismSuperchainERC20ForToBProperties.t.sol";
import { Predeploys } from "src/libraries/Predeploys.sol";
import { MockL2ToL2CrossDomainMessenger } from "../helpers/MockL2ToL2CrossDomainMessenger.t.sol";
import { Actors } from "../helpers/Actors.t.sol";

contract ProtocolHandler is TestBase, StdUtils, Actors {
    using EnumerableMap for EnumerableMap.Bytes32ToUintMap;

    uint8 public constant MAX_CHAINS = 4;
    uint8 internal constant INITIAL_TOKENS = 1;
    uint8 internal constant INITIAL_SUPERTOKENS = 1;
    uint8 internal constant SUPERTOKEN_INITIAL_MINT = 100;
    address internal constant BRIDGE = Predeploys.L2_STANDARD_BRIDGE;
    MockL2ToL2CrossDomainMessenger internal constant MESSENGER =
        MockL2ToL2CrossDomainMessenger(Predeploys.L2_TO_L2_CROSS_DOMAIN_MESSENGER);
    OptimismSuperchainERC20 internal superchainERC20Impl;
    // NOTE: having more options for this enables the fuzzer to configure
    // different supertokens for the same remote token
    string[] internal WORDS = ["TOKENS"];
    uint8[] internal DECIMALS = [6, 18];

    struct TokenDeployParams {
        uint8 remoteTokenIndex;
        uint8 nameIndex;
        uint8 symbolIndex;
        uint8 decimalsIndex;
    }

    address[] internal remoteTokens;
    address[] internal allSuperTokens;

    /// @notice  'real' deploy salt => total supply sum across chains
    EnumerableMap.Bytes32ToUintMap internal ghost_totalSupplyAcrossChains;
    /// @notice  'real' deploy salt => tokens sendERC20'd but not yet relayERC20'd
    EnumerableMap.Bytes32ToUintMap internal ghost_tokensInTransit;

    constructor() {
        vm.etch(address(MESSENGER), address(new MockL2ToL2CrossDomainMessenger()).code);
        superchainERC20Impl = new OptimismSuperchainERC20ForToBProperties();
        for (uint256 remoteTokenIndex; remoteTokenIndex < INITIAL_TOKENS; remoteTokenIndex++) {
            _deployRemoteToken();
            for (uint256 supertokenChainId; supertokenChainId < INITIAL_SUPERTOKENS; supertokenChainId++) {
                _deploySupertoken(remoteTokens[remoteTokenIndex], WORDS[0], WORDS[0], DECIMALS[0], supertokenChainId);
            }
        }
        // integrate with all ToB properties using address(this) as the sender
        addActor(address(this));
    }

    /// @notice the deploy params are _indexes_ to pick from a pre-defined array of options and limit
    /// the amount of supertokens for a given remoteAsset that are incompatible between them, as
    /// two supertokens have to share decimals, name, symbol and remoteAsset to be considered
    /// the same asset, and therefore bridgable.
    modifier validateTokenDeployParams(TokenDeployParams memory params) {
        params.remoteTokenIndex = uint8(bound(params.remoteTokenIndex, 0, remoteTokens.length - 1));
        params.nameIndex = uint8(bound(params.nameIndex, 0, WORDS.length - 1));
        params.symbolIndex = uint8(bound(params.symbolIndex, 0, WORDS.length - 1));
        params.decimalsIndex = uint8(bound(params.decimalsIndex, 0, DECIMALS.length - 1));
        _;
    }

    function handler_mockNewRemoteToken() external {
        _deployRemoteToken();
    }

    /// @notice pick one already-deployed supertoken and mint an arbitrary amount of it
    /// necessary so there is something to be bridged :D
    /// TODO: will be replaced when testing the factories and `convert()`
    function handler_mintSupertoken(uint256 index, uint96 amount) external withActor(msg.sender) {
        index = bound(index, 0, allSuperTokens.length - 1);
        address addr = allSuperTokens[index];
        vm.prank(BRIDGE);
        OptimismSuperchainERC20(addr).crosschainMint(currentActor(), amount);
        // currentValue will be zero if key is not present
        (, uint256 currentValue) = ghost_totalSupplyAcrossChains.tryGet(MESSENGER.superTokenInitDeploySalts(addr));
        ghost_totalSupplyAcrossChains.set(MESSENGER.superTokenInitDeploySalts(addr), currentValue + amount);
    }

    /// @notice The ToB properties don't preclude the need for this since they
    /// always use address(this) as the caller, which won't get any balance
    /// until it's transferred to it somehow
    function handler_supERC20Transfer(
        uint256 tokenIndex,
        uint256 toIndex,
        uint256 amount
    )
        external
        withActor(msg.sender)
    {
        vm.prank(currentActor());
        OptimismSuperchainERC20(allSuperTokens[bound(tokenIndex, 0, allSuperTokens.length)]).transfer(
            getActorByRawIndex(toIndex), amount
        );
    }

    function handler_supERC20TransferFrom(
        uint256 tokenIndex,
        uint256 fromIndex,
        uint256 toIndex,
        uint256 amount
    )
        external
        withActor(msg.sender)
    {
        vm.prank(currentActor());
        OptimismSuperchainERC20(allSuperTokens[bound(tokenIndex, 0, allSuperTokens.length)]).transferFrom(
            getActorByRawIndex(fromIndex), getActorByRawIndex(toIndex), amount
        );
    }

    function handler_supERC20Approve(
        uint256 tokenIndex,
        uint256 spenderIndex,
        uint256 amount
    )
        external
        withActor(msg.sender)
    {
        vm.prank(currentActor());
        OptimismSuperchainERC20(allSuperTokens[bound(tokenIndex, 0, allSuperTokens.length)]).approve(
            getActorByRawIndex(spenderIndex), amount
        );
    }

    /// @notice deploy a remote token, that supertokens will be a representation of. They are  never called, so there
    /// is no need to actually deploy a contract for them
    function _deployRemoteToken() internal {
        // make sure they don't conflict with predeploys/preinstalls/precompiles/other tokens
        remoteTokens.push(address(uint160(1000 + remoteTokens.length)));
    }

    /// @notice deploy a new supertoken representing remoteToken
    /// remoteToken, name, symbol and decimals determine the 'real' deploy salt
    /// and supertokens sharing it are interoperable between them
    /// we however use the chainId as part of the deploy salt to mock the ability of
    /// supertokens to exist on different chains on a single EVM.
    function _deploySupertoken(
        address remoteToken,
        string memory name,
        string memory symbol,
        uint8 decimals,
        uint256 chainId
    )
        internal
        returns (OptimismSuperchainERC20 supertoken_)
    {
        // this salt would be used in production. Tokens sharing it will be bridgable with each other
        bytes32 realSalt = keccak256(abi.encode(remoteToken, name, symbol, decimals));
        // Foundry invariant erroneously show other unrelated invariant breaking
        // when this deployment fails due to a create2 collision, so we revert eagerly instead
        require(
            MESSENGER.superTokenAddresses(chainId, realSalt) == address(0), "ProtocolHandler: skip duplicate deployment"
        );

        // what we use in the tests to walk around two contracts needing two different addresses
        // tbf we could be using CREATE1, but this feels more verbose
        bytes32 hackySalt = keccak256(abi.encode(remoteToken, name, symbol, decimals, chainId));
        supertoken_ = OptimismSuperchainERC20(
            address(
                // TODO: Use the OptimismSuperchainERC20 Beacon Proxy
                new ERC1967Proxy{ salt: hackySalt }(
                    address(superchainERC20Impl),
                    abi.encodeCall(OptimismSuperchainERC20.initialize, (remoteToken, name, symbol, decimals))
                )
            )
        );
        MESSENGER.registerSupertoken(realSalt, chainId, address(supertoken_));
        allSuperTokens.push(address(supertoken_));
    }
}

